/* ==========================================================================
   PL/SW IDE -- App styles (Catppuccin Mocha theme)
   ========================================================================== */

/* --- 3-column wizard layout --- */
.plsw-wizard-layout {
    display: grid;
    grid-template-columns: 120px 150px 1fr;
    height: 100%;
    overflow: hidden;
}

/* Column 1: Sidebar with buttons */
.wizard-sidebar {
    display: flex;
    flex-direction: column;
    padding: 8px;
    background: var(--mantle);
    border-right: 1px solid var(--surface1);
    gap: 8px;
}

.sidebar-section {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.sidebar-section-label {
    font-size: 0.7em;
    color: var(--overlay0);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    padding: 0 4px;
}

.sidebar-btn {
    width: 100%;
    padding: 7px 8px;
    background: var(--surface0);
    color: var(--blue);
    border: 1px solid var(--surface1);
    border-radius: 4px;
    cursor: pointer;
    font-family: var(--mono);
    font-weight: bold;
    font-size: 0.75em;
    transition: all 0.15s;
}

.sidebar-btn:hover {
    background: var(--surface1);
    border-color: var(--blue);
}

.sidebar-select {
    width: 100%;
    padding: 6px 8px;
    background: var(--surface0);
    color: var(--text);
    border: 1px solid var(--surface1);
    border-radius: 4px;
    font-family: var(--mono);
    font-size: 0.75em;
    cursor: pointer;
}

.sidebar-select:focus {
    outline: none;
    border-color: var(--blue);
}

.sidebar-spacer {
    flex: 1;
}

.sidebar-link {
    display: block;
    padding: 7px 8px;
    color: var(--overlay2);
    text-decoration: none;
    font-size: 0.75em;
    font-weight: bold;
    border-radius: 4px;
    transition: color 0.15s;
}

.sidebar-link:hover {
    color: var(--blue);
}

.sidebar-link .ext-icon {
    font-size: 0.8em;
}

/* Column 2: Wizard steps */
.wizard-steps {
    display: flex;
    flex-direction: column;
    padding: 12px;
    background: var(--crust);
    border-right: 1px solid var(--surface1);
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    border-radius: 4px;
    margin-bottom: 3px;
    cursor: default;
    transition: all 0.15s;
    border: 1px solid transparent;
}

.wizard-step.active {
    background: var(--surface0);
    border-color: var(--blue);
}

.wizard-step.completed {
    cursor: pointer;
}

.wizard-step.completed:hover {
    background: rgba(137, 180, 250, 0.08);
}

.wizard-step.completed .step-indicator {
    color: var(--green);
}

.wizard-step.disabled {
    opacity: 0.35;
}

.step-indicator {
    font-size: 1em;
    width: 18px;
    text-align: center;
    color: var(--blue);
}

.step-label {
    color: var(--subtext1);
    font-size: 0.8em;
}

.wizard-action-btn {
    margin-top: 14px;
    padding: 9px 14px;
    background: var(--blue);
    color: var(--crust);
    border: none;
    border-radius: 4px;
    font-family: var(--mono);
    font-weight: bold;
    font-size: 0.82em;
    cursor: pointer;
    transition: all 0.2s;
    animation: wizard-btn-glow 1.8s ease-in-out infinite;
}

@keyframes wizard-btn-glow {
    0%, 100% {
        box-shadow: 0 0 8px rgba(137, 180, 250, 0.5), 0 0 16px rgba(137, 180, 250, 0.3);
        transform: scale(1);
    }
    50% {
